import{_ as t,o,c as n,ag as s}from"./chunks/framework.6ZJjlmu_.js";const u=JSON.parse('{"title":"Generate the demo scene","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/demo-scene.md","filePath":"how-to/demo-scene.md"}'),r={name:"how-to/demo-scene.md"};function a(i,e,l,c,d,g){return o(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="generate-the-demo-scene" tabindex="-1">Generate the demo scene <a class="header-anchor" href="#generate-the-demo-scene" aria-label="Permalink to &quot;Generate the demo scene&quot;">​</a></h1><p><strong>Goal:</strong> Create a ready-made Unity scene that fires sample events so you can verify <strong>SUB</strong> and <strong>INVOKE</strong> rows without writing code — and exercise <strong>1.1+</strong> diagnostics (leaks, growth alerts, timing, exceptions, diff view).</p><p><strong>Prerequisites:</strong> Event Monitor Editor extension installed (menu item present).</p><h2 id="pre-included-scene-asset-store-package" tabindex="-1">Pre-included scene (Asset Store / package) <a class="header-anchor" href="#pre-included-scene-asset-store-package" aria-label="Permalink to &quot;Pre-included scene (Asset Store / package)&quot;">​</a></h2><p>The package ships a ready-made demo scene at:</p><p><code>Assets/EventMonitor/Demo/EventMonitor_Demo.unity</code></p><p>Open it in the Editor, enable <strong>Record</strong> in <strong>Window → Event Monitor</strong>, enter Play Mode, and click the labeled buttons. No menu generation required.</p><h2 id="regenerate-via-menu" tabindex="-1">Regenerate via menu <a class="header-anchor" href="#regenerate-via-menu" aria-label="Permalink to &quot;Regenerate via menu&quot;">​</a></h2><p>Use <strong>Tools → Event Monitor → Generate Demo Scene</strong> or <strong>Create Demo Scene</strong> to rebuild the scene (overwrites the file above).</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>In the Unity menu, choose <strong>Tools → Event Monitor → Generate Demo Scene</strong>.</li><li>Confirm the dialog if prompted. The scene is saved to <code>Assets/EventMonitor/Demo/EventMonitor_Demo.unity</code> (also included in the package — you can open it directly without regenerating).</li><li>Open <strong>Window → Event Monitor</strong> and enable <strong>Record</strong>.</li><li>Enter <strong>Play Mode</strong>.</li><li>Click UI buttons (labels show event names), or run <strong>Run sample sequence</strong> / <strong>Random event burst</strong> / <strong>Run showcase (1.1+)</strong>.</li></ol><p>You should see <strong>SUB</strong> lines when listeners attach and <strong>INVOKE</strong> lines when buttons trigger events. A small <strong>HUD</strong> mirrors the last actions for quick visual confirmation.</p><h3 id="multiple-sub-rows-per-event-expected" tabindex="-1">Multiple SUB rows per event (expected) <a class="header-anchor" href="#multiple-sub-rows-per-event-expected" aria-label="Permalink to &quot;Multiple SUB rows per event (expected)&quot;">​</a></h3><p>Several components subscribe to the same event on purpose (for example <strong>PromoDemoGameHud</strong> updates the HUD while <strong>PromoDemoUiListener</strong> / <strong>PromoDemoSoundListener</strong> / <strong>PromoDemoAnalyticsListener</strong> add extra handlers). You will see <strong>one SUB row per distinct handler</strong>, not a duplicate of the same subscription. Static handlers are labeled with their <strong>declaring type</strong> (e.g. <code>PromoDemoUiListener.OnScore</code>), not a generic <code>static</code> bucket.</p><p>The generated demo scene relies on <strong>ILPP</strong> for <code>Assembly-CSharp</code> and does <strong>not</strong> include <code>ReflectionScanner</code> (avoids extra SUB noise from Unity UI internals).</p><h2 id="what-the-demo-includes" tabindex="-1">What the demo includes <a class="header-anchor" href="#what-the-demo-includes" aria-label="Permalink to &quot;What the demo includes&quot;">​</a></h2><p>Typical contents (exact names may vary by version):</p><ul><li><strong>Canvas</strong> — left column: player, game state, enemy controls, and sequence buttons; right column: <strong>Live HUD</strong> and <strong>Diagnostics (1.1+)</strong>.</li><li><strong>Promo / demo buses</strong> — MonoBehaviours exposing C# events (<code>OnPlayerJump</code>, <code>OnScoreChanged</code>, <code>OnEnemySpawned</code>, etc.).</li><li><strong>Listeners</strong> — extra subscribers so the <strong>Subscribers</strong> graph is non-trivial.</li><li><strong>Diagnostics (1.1+)</strong> — buttons to demo: <ul><li><strong>Create leak</strong> — destroyed subscriber without unsubscribe → <a href="./leak-detection.html">Leak detection</a> (Stats tab).</li><li><strong>Simulate subscriber growth</strong> — sustained <code>OnDiagnosticsPing</code> subscriptions → <a href="./subscriber-growth-alerts.html">Growth Alerts</a> tab.</li><li><strong>Throw in handler</strong> — exception with breadcrumb context → <a href="./exception-breadcrumbs.html">Exception breadcrumbs</a> tab.</li><li><strong>Spawn boss (slow)</strong> — busy handler; enable <strong>⏱ Timing</strong> for <a href="./invoke-timing.html">Invoke timing</a>.</li><li><strong>Toggle extra listener</strong> — runtime <code>+=</code> / <code>-=</code> for <a href="./diff-view.html">Diff view</a> on Subscribers.</li><li><strong>Run showcase (1.1+)</strong> — one-click sequence through the features above (good for screen recordings).</li></ul></li></ul><p>Window-only features (no dedicated demo button): <strong>Save…</strong> / <strong>Load…</strong> sessions, <strong>Compare sessions</strong> (Stats), <strong>⚡ Re-fire</strong> (Log detail), <strong>⚙ Assemblies</strong> filter — see linked how-to guides.</p><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="./../guide/quick-start.html">Quick Start</a></li><li><a href="./../concepts/ilpp-vs-reflection-scanner.html">ILPP vs ReflectionScanner</a></li><li><a href="./session-save-load.html">Session save/load</a></li><li><a href="./manual-dispatch.html">Manual dispatch (Re-fire)</a></li></ul>',21)])])}const m=t(r,[["render",a]]);export{u as __pageData,m as default};
